import React, { useState } from 'react'
import { Container, Grid, Paper, Tab, Tabs, makeStyles } from '@material-ui/core'
import StudentActivities from '../components/StudentActivities'
import StudentNewsfeed from '../components/StudentNewsfeed';

  const useStyle = makeStyles(theme => {
    return {
      tabs: {
        width: '100%',
        maxWidth: 400
      }
    }
  })

export default function StudentFeed() {

  const [selectedTab, setSelectedTab] = React.useState(0);
  const classes = useStyle()

  const handleChange = (event, newValue) => {
    setSelectedTab(newValue);
  };

  const [activities, setActivities] = useState([
    { title: 'Assignment 1mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 11', id: 1 },
    { title: 'Assignment 2mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 2', id: 2 },
    { title: 'Assignment 3mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 3', id: 3 },
    { title: 'Assignment 4mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 4', id: 4 },
    { title: 'Assignment 5mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 5', id: 5 },
    { title: 'Assignment 6mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 6', id: 6 },
    { title: 'Assignment 7mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 7', id: 7 },
    { title: 'Assignment 8mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 8', id: 8 },
    { title: 'Assignment 9mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 9', id: 9 },
    { title: 'Assignment 10mahaba mabahabaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa', body: 'May 10', id: 10 },
  ])
  

  return (
    <div>
      <Container>
        <Grid container spacing={3}>

          <Grid item xs={12}>
            <h1>Subject Name here</h1>
            <Paper classes={classes.tabs}>
              <Tabs value={selectedTab} onChange={handleChange} centered>
                <Tab label="NewsFeed" />
                <Tab label="Activities" />
              </Tabs>
            </Paper>
          </Grid>
          
          <Grid item xs={12}>
              {selectedTab === 0 && <StudentNewsfeed title='This is Newsfeed' />}
          </Grid>
          {activities.map(activity => (
            <Grid item xs={12} key={activity.id}>
              {selectedTab === 1 && <StudentActivities activity={activity} />}
            </Grid>
          ))}
        </Grid>
      </Container>
    </div>
  )
}
